class Playground {
  async run(input) {
    const chars = input.split('');
    this.array.init(chars);
    this.log('Start: Checking parentheses balance');
    await this.await();

    const pairMap = { ')': '(', '}': '{', ']': '[' };
    const openSet = new Set(['(', '{', '[']);

    for (let i = 0; i < chars.length; i++) {
      const char = chars[i];
      this.ptr.set('i', i);
      this.array.highlight(i, '#3b82f6');
      this.log(`Scanning index ${i}: '${char}'`);
      await this.await();

      if (openSet.has(char)) {
        this.log(`Found opening '${char}': Push to stack`);
        this.stack.push(char);
        this.array.highlight(i, '#f59e0b');
        await this.await();
      } 
      else if (char in pairMap) {
        this.log(`Found closing '${char}': Check stack top`);

        if (this.stack.isEmpty()) {
          this.log('❌ Error: Stack is empty! No match found.');
          this.array.highlight(i, '#ef4444');
          await this.await();
          return false;
        }

        const top = this.stack.peek();
        this.stack.highlight(this.stack.size() - 1, '#f59e0b');
        await this.await();

        if (top === pairMap[char]) {
          this.stack.pop();
          this.log(`✅ Match! '${top}' matches '${char}'. Popped.`);
          this.array.highlight(i, '#10b981');
          await this.await();
        } else {
          this.log(`❌ Mismatch! Expected closing for '${top}', got '${char}'.`);
          this.array.highlight(i, '#ef4444');
          this.stack.highlight(this.stack.size() - 1, '#ef4444');
          await this.await();
          return false;
        }
      }
    }

    this.ptr.remove('i');
    if (this.stack.isEmpty()) {
      this.log('✅ Stack is empty. All brackets balanced!');
      await this.await();
      return true;
    } else {
      this.log(`❌ Unbalanced: ${this.stack.size()} unclosed bracket(s) left.`);
      await this.await();
      return false;
    }
  }
}
